// NODO: Merge_And_Save_New_Category_FIXED
// VERSIONE: 3.5 - Fix ReferenceError

// ═══════════════════════════════════════════════════════════════════════════
// 1. RECUPERO DATI E VALIDAZIONE
// ═══════════════════════════════════════════════════════════════════════════
const item = $input.first().json;

const existingLibrary = item.service_catalog_setup;
const interfaceConfig = item.interface;
const ownerData = item.owner_data; 
const webhookBody = item.user_request;
const newCategoryBlock = webhookBody.new_category_block;

if (!existingLibrary || !newCategoryBlock || !webhookBody || !ownerData) {
    throw new Error("Input incompleto. Dati mancanti (libreria, nuova categoria, owner_data o body).");
}

// ═══════════════════════════════════════════════════════════════════════════
// 2. LOGICA DI MERGE (ADD/UPDATE CATEGORY)
// ═══════════════════════════════════════════════════════════════════════════
let updatedCategories = JSON.parse(JSON.stringify(existingLibrary.categories));
const categoryExists = updatedCategories.some(cat => cat.callback_data === newCategoryBlock.callback_data);

if (!categoryExists) {
    updatedCategories.push(newCategoryBlock);
} else {
    updatedCategories = updatedCategories.map(cat => 
        cat.callback_data === newCategoryBlock.callback_data ? newCategoryBlock : cat
    );
}

const updatedServiceLibrary = {
    ...existingLibrary,
    categories: updatedCategories,
    metadata: {
        ...(existingLibrary.metadata || {}),
        last_updated_at: new Date().toISOString(),
        updated_by: "USER_VIA_WEB_APP"
    }
};


// ═══════════════════════════════════════════════════════════════════════════
// 4. RETURN
// ═══════════════════════════════════════════════════════════════════════════
return [{
    json: {
        ...item,
        updated_service_library: updatedServiceLibrary
    }
}];

// NODO: Ingress_ID_Sanitizer_V2 (Collision Proof)
// OBIETTIVO: Generare ID deterministici basati sul TEMPO + RANDOM
// POSIZIONE: Subito dopo il Webhook

const item = $input.first().json;
const body = item.body;

if (!body || !body.new_category_block) {
    throw new Error("Payload non valido: new_category_block mancante.");
}

const categoryBlock = body.new_category_block;

// ───────────────────────────────────────────────────────────────
// GENERATORE DI ID "TEMPORALI" (Zero Collisioni)
// ───────────────────────────────────────────────────────────────
function generateUniqueId(prefix) {
    // 1. Parte Temporale: Ultimi 4 caratteri del timestamp in base36
    //    Garantisce che ID generati in momenti diversi siano sempre diversi.
    const timePart = Date.now().toString(36).slice(-4).toUpperCase();

    // 2. Parte Casuale: 5 caratteri random (20 milioni di combinazioni per millisecondo)
    const randomPart = Math.random().toString(36).substring(2, 7).toUpperCase();

    // Es: CAT_K9L1_X5Y8Z (Lunghezza totale ID ~13-14 caratteri)
    return `${prefix}_${timePart}${randomPart}`;
}

// 1. Sanitizzazione Categoria
categoryBlock.callback_data = generateUniqueId("CAT");

// 2. Sanitizzazione Sottocategorie
if (categoryBlock.subcategories && Array.isArray(categoryBlock.subcategories)) {
    categoryBlock.subcategories = categoryBlock.subcategories.map(sub => ({
        ...sub,
        // Generiamo un nuovo ID temporale per ogni servizio
        callback_data: generateUniqueId("SVC") 
    }));
}

// 3. Output
return {
    json: {
        ...item,
        body: {
            ...body,
            new_category_block: categoryBlock
        },
        sanitization: {
            status: "SECURE_TIME_BASED",
            new_cat_id: categoryBlock.callback_data
        }
    }
};

